  1	import * as React from 'react';
  2	import {
  3	  Checkbox,
  4	  Form,
  5	  FormGroup,
  6	  FormHelperText,
  7	  HelperText,
  8	  HelperTextItem,
  9	  MenuToggle,
 10	  Radio,
 11	  Select,
 12	  SelectList,
 13	  SelectOption,
 14	  Switch,
 15	  TextInput
 16	} from '@patternfly/react-core';
 17	import { GATEWAY_TOOLTIP, wizardTooltip } from './WizardHelp';
 18	import { isValid } from 'utils/Common';
 19	import { t } from 'utils/I18nUtils';
 20	
 21	type Props = {
 22	  serviceName: string;
 23	  hasGateway: boolean;
 24	  gateway: string;
 25	  isMesh: boolean;
 26	  gateways: string[];
 27	  vsHosts: string[];
 28	  onGatewayChange: (valid: boolean, gateway: GatewaySelectorState) => void;
 29	};
 30	
 31	export type GatewaySelectorState = {
 32	  addGateway: boolean;
 33	  gwHosts: string;
 34	  gwHostsValid: boolean;
 35	  newGateway: boolean;
 36	  selectedGateway: string;
 37	  gatewayClass: string;
 38	  addMesh: boolean;
 39	  port: number;
 40	  isOpen: boolean;
 41	};
 42	
 43	enum GatewayForm {
 44	  SWITCH,
 45	  MESH,
 46	  GW_HOSTS,
 47	  SELECT,
 48	  GATEWAY_SELECTED,
 49	  PORT
 50	}
 51	
 52	export class GatewaySelector extends React.Component<Props, GatewaySelectorState> {
 53	  constructor(props: Props) {
 54	    super(props);
 55	    this.state = {
 56	      addGateway: props.hasGateway,
 57	      gwHosts: '*',
 58	      gwHostsValid: true,
 59	      newGateway: props.gateways.length === 0,
 60	      selectedGateway: props.gateways.length > 0 ? (props.gateway !== '' ? props.gateway : props.gateways[0]) : '',
 61	      gatewayClass: '',
 62	      addMesh: props.isMesh,
 63	      port: 80,
 64	      isOpen: false,
 65	    };
 66	  }
 67	
 68	  onToggleClick = () => {
 69	    this.setState((prevState) => ({ isOpen: !prevState.isOpen }));
 70	  };
 71	
 72	  toggle = (toggleRef: React.Ref<any>) => (
 73	    <MenuToggle
 74	      ref={toggleRef}
 75	      onClick={this.onToggleClick}
 76	      isExpanded={this.state.isOpen} 
 77	      isDisabled={!this.state.addGateway || this.state.newGateway || this.props.gateways.length === 0} 
 78	    >
 79	      {this.state.selectedGateway ?? this.props.gateways[0]}
 80	    </MenuToggle>
 81	  );
 82	
 83	  checkGwHosts = (gwHosts: string): boolean => {
 84	    const hosts = gwHosts.split(',');
 85	    for (let i = 0; i < hosts.length; i++) {
 86	      if (hosts[i] === '*') {
 87	        continue;
 88	      }
 89	      if (!hosts[i].includes('.')) {
 90	        return false;
 91	      }
 92	    }
 93	    return true;
 94	  };
 95	
 96	  onFormChange = (component: GatewayForm, value: string) => {
 97	    switch (component) {
 98	      case GatewayForm.SWITCH:
 99	        this.setState(
100	          prevState => {
101	            return {
102	              addGateway: !prevState.addGateway
103	            };
104	          },
105	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
106	        );
107	        break;
108	      case GatewayForm.MESH:
109	        this.setState(
110	          prevState => {
111	            return {
112	              addMesh: !prevState.addMesh
113	            };
114	          },
115	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
116	        );
117	        break;
118	      case GatewayForm.GW_HOSTS:
119	        this.setState(
120	          {
121	            gwHosts: value,
122	            gwHostsValid: this.checkGwHosts(value)
123	          },
124	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
125	        );
126	        break;
127	      case GatewayForm.SELECT:
128	        this.setState(
129	          {
130	            newGateway: value === 'true'
131	          },
132	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
133	        );
134	        break;
135	      case GatewayForm.GATEWAY_SELECTED:
136	        this.setState(
137	          {
138	            selectedGateway: value,
139	            isOpen: false,
140	          },
141	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
142	        );
143	        break;
144	      case GatewayForm.PORT:
145	        this.setState(
146	          {
147	            port: +value
148	          },
149	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
150	        );
151	        break;
152	      default:
153	      // No default action
154	    }
155	  };
156	
157	  isMeshGatewayValid = (): boolean => {
158	    const hasVsWildcard = this.props.vsHosts.some(h => h === '*');
159	    const hasGwWildcard = this.state.gwHosts.split(',').some(h => h === '*');
160	    // Gateway added
161	    if (this.state.addGateway) {
162	      // Mesh can't use wildcard in the hosts
163	      if (this.state.addMesh) {
164	        if (this.state.newGateway) {
165	          // If mesh, a new gateway can't use wildcard
166	          return !hasGwWildcard;
167	        } else {
168	          // If mesh, a selected gateway can't use wildcard
169	          return !hasVsWildcard;
170	        }
171	      }
172	      return true;
173	    } else {
174	      // No gateway means that mesh is used by default
175	      // Mesh can't use wildcard in the hosts
176	      return !hasVsWildcard;
177	    }
178	  };
179	
180	  isGatewayValid = (): boolean => {
181	    // gwHostsValid is used as last validation, it's true by default
182	    return this.isMeshGatewayValid() && this.state.gwHostsValid;
183	  };
184	
185	  render() {
186	    return (
187	      <Form isHorizontal={true}>
188	        <FormGroup label={t('Add Gateway')} fieldId="gatewaySwitch">
189	          <Switch
190	            id="advanced-gwSwitch"
191	            label={' '}
192	            labelOff={' '}
193	            isChecked={this.state.addGateway}
194	            onChange={() => this.onFormChange(GatewayForm.SWITCH, '')}
195	          />
196	          <span>{wizardTooltip(GATEWAY_TOOLTIP)}</span>
197	        </FormGroup>
198	        {this.state.addGateway && (
199	          <>
200	            <FormGroup fieldId="includeMesh">
201	              <Checkbox
202	                id="includeMesh"
203	                label={
204	                  <>
205	                  {t('Include mesh gateway')}
206	                  </>
207	                }
208	                isDisabled={!this.state.addGateway}
209	                isChecked={this.state.addMesh}
210	                onChange={() => this.onFormChange(GatewayForm.MESH, '')}
211	              />
212	              {!isValid(this.isMeshGatewayValid()) && (
213	                <FormHelperText>
214	                  <HelperText>
215	                    <HelperTextItem>VirtualService Host '*' wildcard not allowed on mesh gateway.</HelperTextItem>
216	                  </HelperText>
217	                </FormHelperText>
218	              )}
219	            </FormGroup>
220	            <FormGroup fieldId="selectGateway">
221	              <Radio
222	                id="existingGateway"
223	                name="selectGateway"
224	                label={t('Select Gateway')}
225	                isDisabled={!this.state.addGateway || this.props.gateways.length === 0}
226	                isChecked={!this.state.newGateway}
227	                onChange={() => this.onFormChange(GatewayForm.SELECT, 'false')}
228	              />
229	              <Radio
230	                id="createGateway"
231	                name="selectGateway"
232	                label={t('Create Gateway')}
233	                isDisabled={!this.state.addGateway}
234	                isChecked={this.state.newGateway}
235	                onChange={() => this.onFormChange(GatewayForm.SELECT, 'true')}
236	              />
237	            </FormGroup>
238	            {!this.state.newGateway && (
239	              <FormGroup fieldId="selectGateway" label={t('Gateway')}>
240	              {this.props.gateways.length > 0 && (
241	                <Select
242	                  id="selectGateway"
243	                  isOpen={this.state.isOpen}
244	                  selected={this.state.selectedGateway}
245	                  onSelect={(_event, gw) => this.onFormChange(GatewayForm.GATEWAY_SELECTED, gw as string)}
246	                  onOpenChange={(isOpen: boolean) => {
247	                    this.setState({ isOpen });
248	                  }}
249	                  toggle={this.toggle}
250	                  shouldFocusToggleOnSelect
251	                >
252	                  <SelectList>
253	                    {this.props.gateways.map(gw => (
254	                      <SelectOption key={gw} value={gw}>
255	                        {gw}
256	                      </SelectOption>
257	                    ))}
258	                  </SelectList>
259	                </Select>
260	              )}
261	              {this.props.gateways.length === 0 && <>There are no gateways to select.</>}
262	            </FormGroup>
263	            )}
264	            {this.state.newGateway && (
265	              <>
266	                <FormGroup fieldId="gwPort" label={t('Port')}>
267	                  <TextInput
268	                    id="gwPort"
269	                    name="gwPort"
270	                    type="number"
271	                    isDisabled={!this.state.addGateway || !this.state.newGateway}
272	                    value={this.state.port}
273	                    onChange={(_event, value) => this.onFormChange(GatewayForm.PORT, value)}
274	                  />
275	                </FormGroup>
276	                <FormGroup fieldId="gwHosts" label={t('Gateway Hosts')}>
277	                  <TextInput
278	                    id="gwHosts"
279	                    name="gwHosts"
280	                    isDisabled={!this.state.addGateway || !this.state.newGateway}
281	                    value={this.state.gwHosts}
282	                    onChange={(_event, value) => this.onFormChange(GatewayForm.GW_HOSTS, value)}
283	                    validated={isValid(this.state.gwHostsValid)}
284	                  />
285	                  <FormHelperText>
286	                    <HelperText>
287	                      <HelperTextItem>
288	                        {isValid(this.state.gwHostsValid)
289	                          ? t('One or more hosts exposed by this gateway. Enter one or multiple hosts separated by comma.')
290	                          : t('Gateway hosts should be specified using FQDN format or \'*\' wildcard.')}
291	                      </HelperTextItem>
292	                    </HelperText>
293	                  </FormHelperText>
294	                </FormGroup>
295	              </>
296	            )}
297	          </>
298	        )}
299	      </Form>
300	    );
301	  }
302	}

